qgt_build_stan_prior_handoff <- function(quasi_geo_result,
                                         min_evidence_score = 35,
                                         max_coef_precision = 25,
                                         min_coef_precision = 2,
                                         single_event_precision = 4) {
  rec <- if (is.list(quasi_geo_result) && !is.null(quasi_geo_result$prior_recommendations)) {
    as.data.table(copy(quasi_geo_result$prior_recommendations))
  } else {
    as.data.table(copy(quasi_geo_result))
  }
  curve_fits <- if (is.list(quasi_geo_result) && !is.null(quasi_geo_result$curve_prior_fits)) {
    as.data.table(copy(quasi_geo_result$curve_prior_fits))
  } else {
    data.table()
  }
  if (!nrow(rec)) return(qgt_empty_stan_prior_handoff())
  required <- c("variable", "coef_prior_mean", "coef_prior_precision", "evidence_direction",
                "max_evidence_score", "event_n", "usable_positive_event_n")
  missing <- setdiff(required, names(rec))
  if (length(missing)) stop("quasi_geo_result prior recommendations are missing required columns: ", paste(missing, collapse = ", "))
  for (cc in c("cost_per_outcome_prior_mean", "roi_like_prior_mean")) if (!cc %in% names(rec)) rec[, (cc) := NA_real_]
  rec <- rec[
    usable_positive_event_n > 0L &
      is.finite(coef_prior_mean) &
      coef_prior_mean > 0 &
      is.finite(max_evidence_score) &
      max_evidence_score >= min_evidence_score &
      evidence_direction %in% c("usable_as_coef_prior", "directional_prior_only")
  ]
  if (!nrow(rec)) return(qgt_empty_stan_prior_handoff())
  rec[, reliability := pmin(1, pmax(0, max_evidence_score / 100))]
  rec[, coef_precision_out := fifelse(
    is.finite(coef_prior_precision) & coef_prior_precision > 0,
    coef_prior_precision,
    fifelse(evidence_direction == "usable_as_coef_prior", single_event_precision * 2, single_event_precision)
  )]
  rec[, coef_precision_out := pmin(max_coef_precision, pmax(min_coef_precision, coef_precision_out * pmax(reliability, 0.25)))]
  rec[, recommended_use_out := fifelse(evidence_direction == "usable_as_coef_prior" & max_evidence_score >= 80,
                                       "calibration_or_tight_directional_prior",
                                       "directional_prior")]
  out <- rec[, .(
    variable = as.character(variable),
    coef = as.numeric(coef_prior_mean),
    coef_precision = as.numeric(coef_precision_out),
    coef_bound = "pos",
    quasi_geo_prior_source = "quasi_geo_channel_specific_marginal_response",
    quasi_geo_evidence_direction = as.character(evidence_direction),
    quasi_geo_recommended_use = as.character(recommended_use_out),
    quasi_geo_max_evidence_score = as.numeric(max_evidence_score),
    quasi_geo_event_n = as.integer(event_n),
    quasi_geo_usable_event_n = as.integer(usable_positive_event_n),
    quasi_geo_cost_per_outcome_prior = as.numeric(cost_per_outcome_prior_mean),
    quasi_geo_roi_like_prior = as.numeric(roi_like_prior_mean)
  )]
  if (nrow(curve_fits) && "variable" %in% names(curve_fits)) {
    curve_keep <- intersect(
      c("variable", "anchor_saturation", "anchor_saturation_sd", "anchor_saturation_precision",
        "curve_type", "dvalue", "recommended_use", "curve_fit_status"),
      names(curve_fits)
    )
    cf <- unique(curve_fits[, ..curve_keep], by = "variable")
    if ("curve_fit_status" %in% names(cf)) {
      weak <- cf$curve_fit_status != "conservative_hill_marginal_response_fit"
      for (cc in intersect(c("anchor_saturation", "anchor_saturation_sd", "anchor_saturation_precision", "dvalue"), names(cf))) {
        data.table::set(cf, which(weak), cc, NA_real_)
      }
      if ("curve_type" %in% names(cf)) data.table::set(cf, which(weak), "curve_type", NA_character_)
    }
    out <- cf[out, on = "variable"]
    if ("recommended_use" %in% names(out)) data.table::setnames(out, "recommended_use", "quasi_geo_curve_recommended_use")
    if ("curve_fit_status" %in% names(out)) {
      out[, quasi_geo_curve_prior_source := fifelse(
        curve_fit_status == "conservative_hill_marginal_response_fit",
        "quasi_geo_uncertainty_weighted_dose_response",
        "quasi_geo_default_anchor_due_to_insufficient_dose_evidence"
      )]
      out[, curve_fit_status := NULL]
    }
  }
  for (cc in setdiff(names(qgt_empty_stan_prior_handoff()), names(out))) out[, (cc) := qgt_empty_stan_prior_handoff()[[cc]]]
  out[, names(qgt_empty_stan_prior_handoff()), with = FALSE]
}
qgt_apply_stan_prior_handoff <- function(metadata_input,
                                         quasi_geo_handoff,
                                         overwrite_existing = FALSE) {
  md <- as.data.table(copy(metadata_input))
  handoff <- as.data.table(copy(quasi_geo_handoff))
  if (!nrow(handoff)) return(md[])
  if (!"variable" %in% names(md)) stop("metadata_input must include variable.")
  if (anyDuplicated(as.character(md$variable))) stop("metadata_input has duplicate variable keys.")
  if (anyDuplicated(as.character(handoff$variable))) stop("quasi_geo_handoff has duplicate variable keys.")
  for (cc in setdiff(names(handoff), names(md))) {
    md[, (cc) := handoff[[cc]][NA_integer_]]
  }
  md[handoff, on = "variable", `:=`(
    coef = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(coef))), i.coef, suppressWarnings(as.numeric(coef))),
    coef_precision = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(coef_precision))), i.coef_precision, suppressWarnings(as.numeric(coef_precision))),
    coef_bound = fifelse(isTRUE(overwrite_existing) | is.na(coef_bound) | !nzchar(as.character(coef_bound)), i.coef_bound, as.character(coef_bound)),
    quasi_geo_prior_source = i.quasi_geo_prior_source,
    quasi_geo_evidence_direction = i.quasi_geo_evidence_direction,
    quasi_geo_recommended_use = i.quasi_geo_recommended_use,
    quasi_geo_max_evidence_score = i.quasi_geo_max_evidence_score,
    quasi_geo_event_n = i.quasi_geo_event_n,
    quasi_geo_usable_event_n = i.quasi_geo_usable_event_n,
    quasi_geo_cost_per_outcome_prior = i.quasi_geo_cost_per_outcome_prior,
    quasi_geo_roi_like_prior = i.quasi_geo_roi_like_prior,
    anchor_saturation = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(anchor_saturation))), i.anchor_saturation, suppressWarnings(as.numeric(anchor_saturation))),
    anchor_saturation_sd = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(anchor_saturation_sd))), i.anchor_saturation_sd, suppressWarnings(as.numeric(anchor_saturation_sd))),
    anchor_saturation_precision = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(anchor_saturation_precision))), i.anchor_saturation_precision, suppressWarnings(as.numeric(anchor_saturation_precision))),
    curve_type = fifelse(isTRUE(overwrite_existing) | is.na(curve_type) | !nzchar(as.character(curve_type)), i.curve_type, as.character(curve_type)),
    dvalue = fifelse(isTRUE(overwrite_existing) | !is.finite(suppressWarnings(as.numeric(dvalue))), i.dvalue, suppressWarnings(as.numeric(dvalue))),
    quasi_geo_curve_prior_source = i.quasi_geo_curve_prior_source,
    quasi_geo_curve_recommended_use = i.quasi_geo_curve_recommended_use
  )]
  md[]
}

qgt_empty_multi_treated_market_estimates <- function() {
  data.table(
    variable = character(), event_start = as.Date(character()), event_end = as.Date(character()),
    ramp_direction = character(), treated_geos = character(), treated_geo_n = integer(),
    estimable_geo_n = integer(), usable_geo_n = integer(), pooled_incremental_outcome = numeric(),
    pooled_incremental_outcome_se = numeric(), pooled_incremental_outcome_ci_low = numeric(),
    pooled_incremental_outcome_ci_high = numeric(), total_incremental_outcome_raw = numeric(),
    total_incremental_spend = numeric(), total_incremental_media = numeric(),
    pooled_marginal_response = numeric(), total_return_prior = numeric(),
    total_cost_per_outcome = numeric(), heterogeneity_q = numeric(), heterogeneity_i2 = numeric(),
    mean_evidence_score = numeric(), evidence_score = numeric(), multi_market_usable = logical(),
    recommended_use = character(), methodology_note = character()
  )
}

qgt_build_multi_treated_market_estimates <- function(event_results) {
  dt <- copy(as.data.table(event_results))
  if (!nrow(dt)) return(qgt_empty_multi_treated_market_estimates())
  for (cc in c("channel_specific_usable", "lift_se", "incremental_outcome_raw", "incremental_spend",
               "incremental_media", "marginal_response", "evidence_score")) {
    if (!cc %in% names(dt)) dt[, (cc) := if (cc == "channel_specific_usable") FALSE else NA_real_]
  }
  dt <- dt[!is.na(geo) & nzchar(as.character(geo)) & is.finite(incremental_outcome)]
  if (!nrow(dt)) return(qgt_empty_multi_treated_market_estimates())
  out <- dt[, {
    z <- .SD[!duplicated(as.character(geo))]
    valid <- z[is.finite(incremental_outcome) & is.finite(lift_se) & lift_se > 1e-8]
    w <- if (nrow(valid)) 1 / valid$lift_se^2 else numeric()
    pooled <- if (length(w)) sum(w * valid$incremental_outcome) / sum(w) else NA_real_
    pooled_se <- if (length(w)) sqrt(1 / sum(w)) else NA_real_
    q <- if (length(w) >= 2L) sum(w * (valid$incremental_outcome - pooled)^2) else NA_real_
    i2 <- if (is.finite(q) && q > 0 && length(w) >= 2L) pmax(0, (q - (length(w) - 1L)) / q) else 0
    usable_n <- sum(z$channel_specific_usable %in% TRUE, na.rm = TRUE)
    mean_score <- mean(z$evidence_score, na.rm = TRUE)
    adjusted_score <- qgt_clip(mean_score * (1 - 0.35 * i2), 0, 100)
    raw_total <- if (any(is.finite(z$incremental_outcome_raw))) sum(z$incremental_outcome_raw, na.rm = TRUE) else NA_real_
    spend_total <- if (any(is.finite(z$incremental_spend))) sum(z$incremental_spend, na.rm = TRUE) else NA_real_
    media_total <- if (any(is.finite(z$incremental_media))) sum(z$incremental_media, na.rm = TRUE) else NA_real_
    multi_usable <- uniqueN(as.character(z$geo)) >= 2L && usable_n >= 2L && is.finite(pooled) && i2 <= 0.75
    list(
      treated_geos = paste(sort(unique(as.character(z$geo))), collapse = "|"),
      treated_geo_n = uniqueN(as.character(z$geo)), estimable_geo_n = nrow(valid), usable_geo_n = usable_n,
      pooled_incremental_outcome = pooled, pooled_incremental_outcome_se = pooled_se,
      pooled_incremental_outcome_ci_low = pooled - 1.96 * pooled_se,
      pooled_incremental_outcome_ci_high = pooled + 1.96 * pooled_se,
      total_incremental_outcome_raw = raw_total, total_incremental_spend = spend_total,
      total_incremental_media = media_total,
      pooled_marginal_response = if (any(is.finite(z$marginal_response))) stats::weighted.mean(z$marginal_response, pmax(z$evidence_score, 1), na.rm = TRUE) else NA_real_,
      total_return_prior = if (is.finite(raw_total) && is.finite(spend_total) && abs(spend_total) > 1e-8) raw_total / spend_total else NA_real_,
      total_cost_per_outcome = if (is.finite(raw_total) && abs(raw_total) > 1e-8 && is.finite(spend_total)) spend_total / raw_total else NA_real_,
      heterogeneity_q = q, heterogeneity_i2 = i2, mean_evidence_score = mean_score,
      evidence_score = adjusted_score, multi_market_usable = multi_usable,
      recommended_use = data.table::fcase(
        multi_usable && adjusted_score >= 70, "calibration",
        multi_usable && adjusted_score >= 35, "directional_prior",
        default = "diagnostic_only"
      ),
      methodology_note = "Inverse-variance pooled treated-market effects; raw business lift and spend are summed across distinct markets. High cross-market heterogeneity downgrades use."
    )
  }, by = .(variable, event_start, event_end, ramp_direction)]
  out <- out[treated_geo_n >= 2L]
  if (!nrow(out)) return(qgt_empty_multi_treated_market_estimates())
  out[]
}
# 025-quasi_geo-runner.R
# Generated by behavior-preserving split of quasi_geo_test.R.

qgt_add_overlap_diagnostics <- function(estimates) {
  if (is.null(estimates) || !nrow(estimates)) return(estimates)
  out <- copy(estimates)
  out[, `:=`(
    overlap_event_n = 0L,
    same_geo_overlap_event_n = 0L,
    overlap_contamination_score = 0
  )]
  for (i in seq_len(nrow(out))) {
    overlaps <- out$event_id != out$event_id[i] &
      out$event_start <= out$event_end[i] &
      out$event_end >= out$event_start[i]
    same_geo <- overlaps & out$geo == out$geo[i]
    out$overlap_event_n[i] <- sum(overlaps, na.rm = TRUE)
    out$same_geo_overlap_event_n[i] <- sum(same_geo, na.rm = TRUE)
    out$overlap_contamination_score[i] <- qgt_clip(0.10 * out$overlap_event_n[i] + 0.20 * out$same_geo_overlap_event_n[i], 0, 1)
  }
  out[overlap_event_n > 0 & !grepl("overlapping_events", diagnostic_reason, fixed = TRUE),
      diagnostic_reason := paste(diagnostic_reason, "overlapping_events", sep = "|")]
  out[]
}

qgt_add_multiple_testing_diagnostics <- function(estimates) {
  if (is.null(estimates) || !nrow(estimates)) return(estimates)
  out <- copy(estimates)
  if (!"donor_placebo_p_value" %in% names(out)) out[, donor_placebo_p_value := NA_real_]
  if (!"time_placebo_p_value" %in% names(out)) out[, time_placebo_p_value := NA_real_]
  out[, placebo_test_p_value := vapply(seq_len(.N), function(i) {
    z <- c(donor_placebo_p_value[i], time_placebo_p_value[i])
    z <- z[is.finite(z)]
    if (length(z)) min(z) else NA_real_
  }, numeric(1))]
  out[, placebo_bh_q_value := {
    z <- placebo_test_p_value
    ans <- rep(NA_real_, .N)
    ok <- is.finite(z)
    if (any(ok)) ans[ok] <- stats::p.adjust(z[ok], method = "BH")
    ans
  }, by = variable]
  out[, multiple_testing_warning := fifelse(
    .N > 1L,
    paste0("BH-adjusted across ", .N, " candidate events for this variable; event discovery remains observational."),
    "Single candidate event; no across-event multiplicity adjustment required."
  ), by = variable]
  out[]
}
run_quasi_geo_test <- function(input_data,
                               date_col,
                               dep_var_col,
                               geo_col,
                               holdout_col = NULL,
                               holdout_value = TRUE,
                               holdout_last_n = 0L,
                               variable_map = NULL,
                               media_cols = character(),
                               control_cols = character(),
                               normalize = c("geo_mean_index", "none"),
                               pre_weeks = 8L,
                               post_weeks = 4L,
                               rolling_window = 8L,
                               min_abs_change = 0,
                               min_pct_change = 0.25,
                               min_robust_z = 1.5,
                               min_volume = 1e-8,
                               media_cutoff_pct = 0.10,
                               donor_contamination_pct = 0.20,
                               other_media_contamination_pct = 0.25,
                               min_donors = 3L,
                               mde_alpha = 0.05,
                               mde_power = 0.80,
                               lambda_grid = 10 ^ seq(-4, 2, length.out = 20),
                               min_evidence_tier_to_keep = NULL,
                               min_evidence_score_to_keep = NULL,
                               min_evidence_score_for_prior = NULL,
                               min_evidence_score_for_calibration = NULL,
                               period_days = 7L,
                               output_dir = NULL,
                               prefix = "quasi_geo") {
  normalize <- match.arg(normalize)
  known_tiers <- c("not_estimable", "weak_noisy_estimate", "moderate_quasi_geo", "strong_quasi_geo")
  if (!is.null(min_evidence_tier_to_keep) && nzchar(as.character(min_evidence_tier_to_keep)[1]) &&
      !as.character(min_evidence_tier_to_keep)[1] %in% known_tiers) {
    stop("Unknown min_evidence_tier_to_keep: ", as.character(min_evidence_tier_to_keep)[1],
         ". Expected one of: ", paste(known_tiers, collapse = ", "))
  }
  dt <- as.data.table(copy(input_data))
  vm <- qgt_parse_variable_map(variable_map, media_cols)
  for (i in seq_len(nrow(vm))) {
    if (is.na(vm$modeled_x_col[i]) || !nzchar(trimws(vm$modeled_x_col[i])) || !vm$modeled_x_col[i] %in% names(dt)) {
      if (vm$variable[i] %in% names(dt)) {
        vm$modeled_x_col[i] <- vm$variable[i]
      } else {
        stop("variable_map row for variable '", vm$variable[i], "' has unrecoverable modeled_x_col. ",
             "Provide modeled_x_col or include a data column named '", vm$variable[i], "'.")
      }
    }
    if (is.na(vm$spend_col[i]) || !nzchar(trimws(vm$spend_col[i]))) vm$spend_col[i] <- vm$modeled_x_col[i]
  }
  req <- unique(c(date_col, dep_var_col, geo_col, holdout_col, vm$modeled_x_col, vm$spend_col, control_cols))
  miss <- setdiff(req, names(dt))
  if (length(miss)) stop("Missing input columns: ", paste(miss, collapse = ", "))
  dt[, (date_col) := qgt_date(get(date_col))]
  data.table::setorderv(dt, c(geo_col, date_col))
  dt[, (dep_var_col) := qgt_num(get(dep_var_col))]
  raw_dep_col <- "..qgt_raw_dep"
  while (raw_dep_col %in% names(dt)) raw_dep_col <- paste0(raw_dep_col, "_")
  dt[, (raw_dep_col) := qgt_num(get(dep_var_col))]
  for (cc in unique(c(vm$modeled_x_col, vm$spend_col, control_cols))) dt[, (cc) := qgt_num(get(cc))]
  holdout_info <- qgt_apply_holdout_flag(
    dt = dt,
    date_col = date_col,
    holdout_col = holdout_col,
    holdout_value = holdout_value,
    holdout_last_n = holdout_last_n
  )
  dt <- holdout_info$data
  holdout_audit <- holdout_info$audit
  vm <- qgt_assign_raw_media_cols(dt, vm)
  vm <- qgt_assign_raw_spend_cols(dt, vm)
  rollup_lookup <- qgt_rollup_lookup(vm)
  if (normalize == "geo_mean_index") {
    dt <- qgt_mean_index_by_geo(dt, unique(c(dep_var_col, vm$modeled_x_col)), geo_col, train_col = "is_qgt_training__")
  }
  dt_estimation <- dt[is_qgt_training__ == TRUE]
  events <- rbindlist(lapply(seq_len(nrow(vm)), function(i) {
    qgt_event_scan_one(
      dt = dt_estimation,
      date_col = date_col,
      geo_col = geo_col,
      variable = vm$variable[i],
      media_col = vm$modeled_x_col[i],
      pre_weeks = pre_weeks,
      post_weeks = post_weeks,
      min_abs_change = min_abs_change,
      min_pct_change = min_pct_change,
      min_robust_z = min_robust_z,
      min_volume = min_volume,
      media_cutoff_pct = media_cutoff_pct,
      rolling_window = rolling_window,
      period_days = period_days
    )
  }), use.names = TRUE, fill = TRUE)
  if (is.null(events) || !nrow(events)) events <- qgt_empty_candidate_events()
  if (nrow(events)) {
    data.table::setorder(events, variable, geo, event_start)
    events <- events[, .SD[1], by = .(variable, geo, event_start)]
  }
  events <- qgt_attach_rollup_metadata(events, rollup_lookup)
  estimates <- if (nrow(events)) rbindlist(lapply(seq_len(nrow(events)), function(ii) {
    ev <- events[ii]
    media_col <- vm[variable == ev$variable[1], modeled_x_col[1]]
    spend_col <- vm[variable == ev$variable[1], raw_spend_col__[1]]
    qgt_estimate_event(
      dt = dt_estimation,
      event = ev,
      date_col = date_col,
      dep_var_col = dep_var_col,
      raw_dep_col = raw_dep_col,
      geo_col = geo_col,
      media_col = media_col,
      raw_media_col = vm[variable == ev$variable[1], raw_media_col__[1]],
      spend_col = spend_col,
      all_media_cols = vm$modeled_x_col,
      all_raw_media_cols = stats::setNames(vm$raw_media_col__, vm$modeled_x_col),
      all_spend_cols = stats::setNames(vm$raw_spend_col__, vm$modeled_x_col),
      control_cols = control_cols,
      pre_weeks = pre_weeks,
      post_weeks = post_weeks,
      min_volume = min_volume,
      donor_contamination_pct = donor_contamination_pct,
      other_media_contamination_pct = other_media_contamination_pct,
      min_donors = min_donors,
      mde_alpha = mde_alpha,
      mde_power = mde_power,
      lambda_grid = lambda_grid
    )
  }), use.names = TRUE, fill = TRUE) else qgt_empty_event_estimates()
  estimates <- qgt_add_overlap_diagnostics(estimates)
  estimates <- qgt_classify_evidence_events(estimates)
  national_diagnostics <- qgt_national_repeated_media_diagnostics(dt_estimation, date_col, geo_col, vm)
  event_estimates_all <- rbindlist(list(estimates, national_diagnostics), use.names = TRUE, fill = TRUE)
  event_estimates_all <- qgt_classify_evidence_events(event_estimates_all)
  event_estimates_all <- qgt_add_multiple_testing_diagnostics(event_estimates_all)
  event_estimates_all <- qgt_attach_rollup_metadata(event_estimates_all, rollup_lookup)
  estimates <- qgt_attach_rollup_metadata(estimates, rollup_lookup)
  prior_events <- copy(event_estimates_all)
  if (!is.null(min_evidence_score_for_prior)) {
    prior_keep <- qgt_num(min_evidence_score_for_prior)[1]
    if (is.finite(prior_keep)) prior_events <- prior_events[evidence_score >= prior_keep]
  }
  calibration_events_all <- copy(event_estimates_all)
  if (!is.null(min_evidence_score_for_calibration)) {
    cal_keep <- qgt_num(min_evidence_score_for_calibration)[1]
    if (is.finite(cal_keep)) calibration_events_all <- calibration_events_all[evidence_score >= cal_keep]
  }
  if (!is.null(min_evidence_tier_to_keep) && nzchar(as.character(min_evidence_tier_to_keep)[1]) && nrow(estimates)) {
    keep_rank <- qgt_evidence_rank(as.character(min_evidence_tier_to_keep)[1])
    estimates <- estimates[qgt_evidence_rank(evidence_tier) >= keep_rank]
  }
  if (!is.null(min_evidence_score_to_keep) && nrow(estimates)) {
    score_keep <- qgt_num(min_evidence_score_to_keep)[1]
    if (is.finite(score_keep)) estimates <- estimates[evidence_score >= score_keep]
  }
  summary_all <- qgt_summarize_dose_response(event_estimates_all)
  summary <- qgt_summarize_dose_response(estimates)
  curve_evidence_points <- qgt_build_curve_evidence_points(event_estimates_all)
  curve_prior_fits <- qgt_fit_conservative_curve_priors(curve_evidence_points)
  multi_treated_market_estimates <- qgt_build_multi_treated_market_estimates(event_estimates_all)
  prior_recommendations <- qgt_build_prior_recommendations(prior_events)
  bundle_prior_recommendations <- qgt_build_bundle_prior_recommendations(prior_events)
  evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "overall")
  variable_evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "variable")
  estimand_evidence_summary <- qgt_build_evidence_summary(event_estimates_all, "estimand")
  rollup_evidence_summary <- qgt_build_rollup_evidence_summary(event_estimates_all)
  summary_all <- qgt_attach_rollup_metadata(summary_all, rollup_lookup)
  summary <- qgt_attach_rollup_metadata(summary, rollup_lookup)
  prior_recommendations <- qgt_attach_rollup_metadata(prior_recommendations, rollup_lookup)
  variable_evidence_summary <- qgt_attach_rollup_metadata(variable_evidence_summary, rollup_lookup)
  calibration_events <- calibration_events_all[recommended_use == "calibration"]
  directional_prior_events <- event_estimates_all[recommended_use == "directional_prior"]
  diagnostic_events <- event_estimates_all[recommended_use == "diagnostic_only"]
  if (!is.null(output_dir) && nzchar(output_dir)) {
    dir.create(output_dir, recursive = TRUE, showWarnings = FALSE)
    fwrite(events, file.path(output_dir, paste0(prefix, "_candidate_events.csv")))
    fwrite(event_estimates_all, file.path(output_dir, paste0(prefix, "_event_estimates_all.csv")))
    fwrite(estimates, file.path(output_dir, paste0(prefix, "_event_estimates.csv")))
    fwrite(calibration_events, file.path(output_dir, paste0(prefix, "_calibration_events.csv")))
    fwrite(directional_prior_events, file.path(output_dir, paste0(prefix, "_directional_prior_events.csv")))
    fwrite(diagnostic_events, file.path(output_dir, paste0(prefix, "_diagnostic_events.csv")))
    fwrite(summary_all, file.path(output_dir, paste0(prefix, "_dose_response_summary_all.csv")))
    fwrite(summary, file.path(output_dir, paste0(prefix, "_dose_response_summary.csv")))
    fwrite(curve_evidence_points, file.path(output_dir, paste0(prefix, "_curve_evidence_points.csv")))
    fwrite(curve_prior_fits, file.path(output_dir, paste0(prefix, "_curve_prior_fits.csv")))
    fwrite(multi_treated_market_estimates, file.path(output_dir, paste0(prefix, "_multi_treated_market_estimates.csv")))
    fwrite(prior_recommendations, file.path(output_dir, paste0(prefix, "_prior_recommendations.csv")))
    fwrite(bundle_prior_recommendations, file.path(output_dir, paste0(prefix, "_bundle_prior_recommendations.csv")))
    fwrite(evidence_summary, file.path(output_dir, paste0(prefix, "_evidence_summary.csv")))
    fwrite(variable_evidence_summary, file.path(output_dir, paste0(prefix, "_variable_evidence_summary.csv")))
    fwrite(estimand_evidence_summary, file.path(output_dir, paste0(prefix, "_estimand_evidence_summary.csv")))
    fwrite(rollup_evidence_summary, file.path(output_dir, paste0(prefix, "_rollup_evidence_summary.csv")))
  }
  normalized_data <- copy(dt)
  raw_media_cols <- intersect(vm$raw_media_col__, names(normalized_data))
  if (length(raw_media_cols)) normalized_data[, (raw_media_cols) := NULL]
  raw_spend_cols <- intersect(vm$raw_spend_col__, names(normalized_data))
  if (length(raw_spend_cols)) normalized_data[, (raw_spend_cols) := NULL]
  if ("is_qgt_training__" %in% names(normalized_data)) normalized_data[, is_qgt_training__ := NULL]
  if (raw_dep_col %in% names(normalized_data)) normalized_data[, (raw_dep_col) := NULL]
  list(
    package_info = econimap_output_metadata("run_quasi_geo_test", surface = "quasi_geo_evidence"),
    candidate_events = events[],
    event_estimates_all = event_estimates_all[],
    event_estimates = estimates[],
    calibration_events = calibration_events[],
    directional_prior_events = directional_prior_events[],
    diagnostic_events = diagnostic_events[],
    dose_response_summary_all = summary_all[],
    dose_response_summary = summary[],
    curve_evidence_points = curve_evidence_points[],
    curve_prior_fits = curve_prior_fits[],
    multi_treated_market_estimates = multi_treated_market_estimates[],
    prior_recommendations = prior_recommendations[],
    bundle_prior_recommendations = bundle_prior_recommendations[],
    evidence_summary = evidence_summary[],
    variable_evidence_summary = variable_evidence_summary[],
    estimand_evidence_summary = estimand_evidence_summary[],
    rollup_evidence_summary = rollup_evidence_summary[],
    holdout_audit = holdout_audit,
    normalized_data = normalized_data[],
    notes = c(
      "Designed to detect natural or unannounced geo tests.",
      "Event detection is signed: up ramps, down ramps, mixed ramps, and media cutoffs are retained.",
      "No default hard qualification is applied; events are estimated when possible and diagnosed afterward with numeric evidence_score.",
      "False-positive review includes repeated pre-period time placebos, donor-geo placebos, BH multiplicity warnings, and leave-one-donor-out sensitivity diagnostics.",
      "Ridge synthetic-control lambda uses blocked pre-period time validation when history is sufficient.",
      "Multiple channel-specific support levels can yield an uncertainty-weighted conservative curve prior; weak/confounded points remain diagnostic.",
      "Concurrent treated markets are pooled with inverse-variance weighting and heterogeneity diagnostics without double-counting them into event-level priors.",
      "evidence_score_0_100 is an analyst-facing ranking/filter built from GeoLift/matched-market-style diagnostics, not statistical proof.",
      "Use min_evidence_score_to_keep or min_evidence_tier_to_keep only for optional reporting/sensitivity filtering; prior generation uses min_evidence_score_for_prior.",
      "normalize = 'geo_mean_index' is the fallback when population or comparable exposure denominators are unavailable."
    )
  )
}
